using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(int count = 1) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem
            {
                ProductName = $"Product {i}",
                Price = 10m * i,
                Quantity = i
            })
            .ToList();

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 25.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 15.00m, Quantity = 3 },
        };

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual("customer-1", order.CustomerId);
        Assert.AreEqual(95.00m, order.Total); // (25*2) + (15*3)
        Assert.HasCount(2, order.Items);
        Assert.IsNotNull(order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems();

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("customer-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("customer-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.UtcNow;

        // Act
        var order = _service.CreateOrder("customer-1", CreateItems());

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        // Arrange
        var created = _service.CreateOrder("customer-1", CreateItems());

        // Act
        var retrieved = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("nonexistent-id");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        // Arrange
        _service.CreateOrder("customer-A", CreateItems());
        _service.CreateOrder("customer-A", CreateItems(2));
        _service.CreateOrder("customer-B", CreateItems());

        // Act
        var orders = _service.GetOrdersByCustomer("customer-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("no-such-customer");

        Assert.IsEmpty(orders);
    }

    [TestMethod]
    [DataRow(1, 10, 1, 10.00, DisplayName = "Single item")]
    [DataRow(5, 3, 2, 30.00, DisplayName = "Multiple quantity")]
    public void CreateOrder_CalculatesTotalCorrectly(
        int itemCount, decimal price, int quantity, decimal expectedTotal)
    {
        // Arrange
        var items = Enumerable.Range(0, itemCount)
            .Select(_ => new OrderItem
            {
                ProductName = "Item",
                Price = price,
                Quantity = quantity
            })
            .ToList();

        // Act
        var order = _service.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual(expectedTotal * itemCount, order.Total);
    }
}

